class Solution(object):
    def numberOfStableArrays(self, zero, one, limit):
        MOD = 10**9 + 7
        # dp[i][j][c] = # stable arrays with i zeros, j ones, last element = c
        # c=0 means last is 0, c=1 means last is 1
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(z, o, last):
            if z == 0 and o == 0:
                return 1
            res = 0
            if last != 0:  # append 0
                if z > 0:
                    res = (res + dp(z-1, o, 0)) % MOD
            if last != 1:  # append 1
                if o > 0:
                    res = (res + dp(z, o-1, 1)) % MOD
            return res
        # This doesn't handle the 'limit' constraint properly. Use proper DP.
        # dp[z][o][c] = # of stable arrays using z zeros, o ones, ending with c
        # Transition: from dp[z'][o'][c'] where last run of c' doesn't exceed limit
        # Better: dp[z][o][c] directly with inclusion-exclusion
        # dp[z][o][0] = sum over run length r=1..limit: dp[z-r][o][1]
        # dp[z][o][1] = sum over run length r=1..limit: dp[z][o-r][0]
        # Base: dp[0][0][*] = 0, dp[r][0][0] = 1 if r<=limit else 0, etc.
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def f(z, o, last):
            # arrays with exactly z zeros and o ones, last element = last
            if z < 0 or o < 0:
                return 0
            if z == 0 and o == 0:
                return 1
            if last == 0:
                # Last run is zeros, length r. Previous must end with 1 (or start).
                res = 0
                for r in range(1, min(z, limit) + 1):
                    if z - r == 0 and o == 0:
                        if r <= limit:
                            res = (res + 1) % MOD
                    else:
                        res = (res + f(z - r, o, 1)) % MOD
                return res
            else:
                res = 0
                for r in range(1, min(o, limit) + 1):
                    if o - r == 0 and z == 0:
                        if r <= limit:
                            res = (res + 1) % MOD
                    else:
                        res = (res + f(z, o - r, 0)) % MOD
                return res
        return (f(zero, one, 0) + f(zero, one, 1)) % MOD
